// ============================================================
// Mini's IPA Repo — Configuration Constants
// ============================================================

// Derive the site base URL from the current location so that forks,
// staging environments, and local dev all work without code changes.
// e.g. https://oofmini.github.io/Minis-Repo/ on production,
//      http://localhost:5173/  on Vite dev server.
const _raw = window.location.origin + window.location.pathname;
const _BASE_URL = _raw.endsWith('/') ? _raw : _raw + '/';

export const CONFIG = {
    /** mini.json endpoint */
    API_ENDPOINT: `${_BASE_URL}mini.json`,

    /** Fallback icon if app icon fails to load */
    FALLBACK_ICON: './apps/repo-icon.png',

    /** Featured app bundle ID */
    FEATURED_BUNDLE_ID: 'com.spotify.client',

    /** Search debounce in ms */
    SEARCH_DEBOUNCE: 150,

    /** Toast display duration in ms */
    TOAST_DURATION: 4000,

    /** Network fetch timeout in ms */
    FETCH_TIMEOUT: 10_000,

    /** Virtual scroll: pool size (max DOM card nodes) */
    CARD_POOL_SIZE: 24,

    /** Card row height in px (iOS-style cell: icon + text) */
    CARD_ROW_HEIGHT: 88,

    /** Gap between cards in px */
    CARD_GAP: 12,

    /** SW update check interval (30 min) */
    SW_UPDATE_INTERVAL: 30 * 60 * 1000,

    /** Max recent searches to store */
    MAX_RECENT_SEARCHES: 5,

    /** IndexedDB database name (main app) */
    IDB_NAME: 'minis-repo',

    /** IndexedDB version */
    IDB_VERSION: 1,

    /** IndexedDB database name used by the service worker */
    IDB_SW_NAME: 'minis-repo-sw',

    /** Spring animation: bouncy entry */
    SPRING_BOUNCY: 'cubic-bezier(0.175, 0.885, 0.32, 1.275)',

    /** Spring animation: smooth exit */
    SPRING_SMOOTH: 'cubic-bezier(0.4, 0, 0.2, 1)',

    /** Default minimum iOS version shown when a version entry omits minOSVersion */
    DEFAULT_MIN_OS: '15.0',

    /** App base URL — always ends with '/' so hash fragments concatenate cleanly */
    BASE_URL: _BASE_URL,

    // ── Animation / Interaction Timings ──────────────────────

    /** GET button: spinner phase duration in ms */
    BTN_SPINNER_DURATION: 800,
    /** GET button: checkmark hold duration in ms */
    BTN_CHECK_DURATION: 2000,
    /** GET button: checkmark hold for reduced-motion users in ms */
    BTN_CHECK_REDUCED_DURATION: 1500,
    /** GET button: error flash duration in ms */
    BTN_ERROR_FLASH_DURATION: 1200,
    /** Tint rgba cache: max entries before eviction */
    TINT_CACHE_MAX: 100,
    /** Slow network: ms before showing a "Loading…" toast */
    SLOW_LOAD_THRESHOLD: 3000,
    /** Icon preload link: safety-net removal timeout in ms */
    PRELOAD_TIMEOUT: 15_000,
    /** Hash-route modal open delay in ms (lets layout settle before locking scroll) */
    HASH_ROUTE_DELAY: 100,
    /** "More by developer" modal chain delay in ms */
    MODAL_MORE_DELAY: 300,
    /** Copy-button reset delay in ms (how long the "Copied!" state shows) */
    COPY_RESET_DURATION: 2000,
    /** Modal image preload safety-net removal timeout in ms (longer than card icons
     *  because screenshots are larger and take more time to fetch) */
    MODAL_PRELOAD_TIMEOUT: 30_000,
} as const;
